 48вҶ’function resolveSupportBeamLabel(project, floorId, beamId) {
 49вҶ’  if (!beamId) return 'None';
 50вҶ’
 51вҶ’  const floor = (project?.floors || []).find((entry) => entry.id === floorId) || null;
 52вҶ’  const beam = (floor?.beams || []).find((entry) => entry.id === beamId) || null;
 53вҶ’  if (!floor || !beam) {
 54вҶ’    return 'Missing beam';
 55вҶ’  }
 56вҶ’  return getBeamDisplayLabel(beam, floor.columns || []);
 57вҶ’}
