 53вҶ’export function RoofEmptyState({ project, dispatch, editorDispatch, activePhaseId = null }) {
 54вҶ’  const attachableTrussSystems = getAttachableRoofTrussSystems(project);
 55вҶ’  const [selectedTrussSystemId, setSelectedTrussSystemId] = useState(attachableTrussSystems[0]?.id || '');
 56вҶ’
 57вҶ’  useEffect(() => {
 58вҶ’    if (!attachableTrussSystems.some((entry) => entry.id === selectedTrussSystemId)) {
 59вҶ’      setSelectedTrussSystemId(attachableTrussSystems[0]?.id || '');
 60вҶ’    }
 61вҶ’  }, [attachableTrussSystems, selectedTrussSystemId]);
 62вҶ’
 63вҶ’  const selectedTrussSystem = attachableTrussSystems.find((entry) => entry.id === selectedTrussSystemId) || null;
 64вҶ’  const selectedRoofType = selectedTrussSystem
 65вҶ’    ? resolveTrussSystemRoofAttachmentType(selectedTrussSystem)
 66вҶ’    : null;
 67вҶ’  const handleCreate = () => {
 68вҶ’    const roofSystem = createRoofSystemForProject(project, {
 69вҶ’      phaseId: activePhaseId || null,
 70вҶ’      trussAttachmentId: selectedTrussSystemId || null,
 71вҶ’    });
 72вҶ’    if (!roofSystem) return;
 73вҶ’    dispatch({ type: 'ROOF_CREATE', roofSystem });
 74вҶ’    editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'roof' });
 75вҶ’    editorDispatch({ type: 'SELECT_OBJECT', id: roofSystem.id, objectType: 'roofSystem' });
 76вҶ’  };
 77вҶ’
 78вҶ’  return (
 79вҶ’    <div>
