 38вҶ’export function useEditorTool({ activeTool, dispatch, editorDispatch, project, getFloor, activeFloorId, roofSystem, trussSystems, modelTarget, viewport, snapEnabled, selectedId, selectedType, toolState, viewMode, activePhaseId }) {
 39вҶ’  const getFloorRef = useRef(getFloor);
 40вҶ’  getFloorRef.current = getFloor;
 41вҶ’
 42вҶ’  const handler = useMemo(() => {
 43вҶ’    if (modelTarget === 'truss') {
 44вҶ’      if (viewMode !== 'plan') {
 45вҶ’        return createReadOnlyHandler();
 46вҶ’      }
 47вҶ’
 48вҶ’      const trussCtx = {
 49вҶ’        dispatch,
 50вҶ’        editorDispatch,
 51вҶ’        getFloor: (...args) => getFloorRef.current(...args),
 52вҶ’        activeFloorId,
 53вҶ’        trussSystems,
 54вҶ’        viewport,
 55вҶ’        selectedId,
 56вҶ’        selectedType,
 57вҶ’        viewMode,
 58вҶ’      };
 59вҶ’
 60вҶ’      switch (activeTool) {
 61вҶ’        case TOOLS.TRUSS_DRAW:
 62вҶ’          return createTrussDrawHandler(trussCtx);
 63вҶ’        case TOOLS.SELECT:
 64вҶ’        default:
 65вҶ’          return createTrussSelectHandler(trussCtx);
 66вҶ’      }
 67вҶ’    }
 68вҶ’
 69вҶ’    if (modelTarget === 'roof') {
 70вҶ’      if (viewMode !== 'plan') {
 71вҶ’        return createReadOnlyHandler();
 72вҶ’      }
 73вҶ’
 74вҶ’      const roofCtx = {
 75вҶ’        dispatch,
 76вҶ’        editorDispatch,
 77вҶ’        roofSystem,
 78вҶ’        viewport,
 79вҶ’      };
 80вҶ’
 81вҶ’      switch (activeTool) {
 82вҶ’        case TOOLS.ROOF_PARAPET:
 83вҶ’          return createRoofParapetPlaceHandler(roofCtx);
 84вҶ’        case TOOLS.ROOF_DRAIN:
 85вҶ’          return createRoofDrainPlaceHandler(roofCtx);
 86вҶ’        case TOOLS.ROOF_OPENING:
 87вҶ’          return createRoofOpeningPlaceHandler(roofCtx);
 88вҶ’        case TOOLS.SELECT:
 89вҶ’        default:
 90вҶ’          return createRoofSelectHandler(roofCtx);
