100вҶ’        activeFloorId,
101вҶ’        viewport,
102вҶ’        snapEnabled,
103вҶ’        viewMode,
104вҶ’      });
105вҶ’    }
106вҶ’
107вҶ’    if (viewMode !== 'plan') {
108вҶ’      return createReadOnlyHandler();
109вҶ’    }
110вҶ’
111вҶ’    const ctx = {
112вҶ’      dispatch, editorDispatch,
113вҶ’      getFloor: (...args) => getFloorRef.current(...args),
114вҶ’      activeFloorId, viewport, snapEnabled, activePhaseId,
115вҶ’    };
116вҶ’
117вҶ’    switch (activeTool) {
118вҶ’      case TOOLS.DIMENSION:
119вҶ’        return createDimensionPlaceHandler(ctx);
120вҶ’      case TOOLS.WALL:
121вҶ’        return createWallDrawHandler(ctx);
122вҶ’      case TOOLS.BEAM:
123вҶ’        return createBeamPlaceHandler(ctx);
124вҶ’      case TOOLS.STAIR:
125вҶ’        return createStairPlaceHandler(ctx);
126вҶ’      case TOOLS.SECTION:
127вҶ’        return createSectionPlaceHandler(ctx);
128вҶ’      case TOOLS.SLAB:
129вҶ’        return createSlabPlaceHandler(ctx);
130вҶ’      case TOOLS.ROOM:
131вҶ’        return createRoomPlaceHandler(ctx);
132вҶ’      case TOOLS.SELECT:
133вҶ’        return createSelectHandler(ctx);
134вҶ’      case TOOLS.DOOR:
135вҶ’        return createDoorPlaceHandler(ctx);
136вҶ’      case TOOLS.WINDOW:
137вҶ’        return createWindowPlaceHandler(ctx);
138вҶ’      case TOOLS.COLUMN:
139вҶ’        return createColumnPlaceHandler(ctx);
140вҶ’      case TOOLS.LANDING:
141вҶ’        return createLandingPlaceHandler(ctx);
142вҶ’      case TOOLS.FIXTURE:
143вҶ’        return createFixturePlaceHandler(ctx);
144вҶ’      case TOOLS.RAILING:
145вҶ’        return createRailingPlaceHandler(ctx);
146вҶ’      default:
147вҶ’        return null;
148вҶ’    }
149вҶ’  }, [activeTool, activeFloorId, project, roofSystem, trussSystems, modelTarget, viewport.zoom, snapEnabled, viewMode, activePhaseId, selectedId, selectedType]);
150вҶ’
151вҶ’  return {
152вҶ’    onMouseDown: (modelPos, e) => handler?.onMouseDown?.(modelPos, e, toolState),
153вҶ’    onMouseMove: (modelPos, e) => handler?.onMouseMove?.(modelPos, e, toolState, selectedId, selectedType),
154вҶ’    onMouseUp: (modelPos, e) => handler?.onMouseUp?.(modelPos, e, toolState),
155вҶ’    onDoubleClick: (modelPos, e) => handler?.onDoubleClick?.(modelPos, e, toolState),
156вҶ’    onKeyDown: (e) => handler?.onKeyDown?.(e, toolState, selectedId, selectedType),
157вҶ’    getCursor: () => handler?.getCursor?.(toolState) || 'default',
158вҶ’  };
159вҶ’}
