  4вҶ’import { usePlanClipboardController } from '@/clipboard/usePlanClipboardController';
  5вҶ’import { TOOLS } from '@/editor/tools';
  6вҶ’import { detectRooms } from '@/geometry/roomDetection';
  7вҶ’import { createRoom } from '@/domain/models';
  8вҶ’import { isTypingTarget } from '@/utils/keyboard';
  9вҶ’import {
 10вҶ’  NewIcon, SaveIcon, LoadIcon, UndoIcon, RedoIcon,
 11вҶ’  CopyIcon, CutIcon, PasteIcon,
 12вҶ’  SelectIcon, DimensionIcon, WallIcon, BeamIcon, StairIcon,
 13вҶ’  TrussDrawIcon,
 14вҶ’  SectionCutIcon, SlabIcon, RoomIcon, DoorIcon, WindowIcon,
 15вҶ’  ColumnIcon, LandingIcon, RailingIcon,
 16вҶ’  ParapetIcon, DrainIcon, OpeningIcon,
 17вҶ’  KitchenTopIcon, ToiletIcon, LavatoryIcon, TableIcon, TVIcon, SofaIcon, BedIcon,
