 24вҶ’
 25вҶ’const viewModes = [
 26вҶ’  { key: 'plan', label: 'Plan', viewMode: 'plan' },
 27вҶ’  { key: 'front', label: 'Front', viewMode: 'elevation_front' },
 28вҶ’  { key: 'rear', label: 'Rear', viewMode: 'elevation_rear' },
 29вҶ’  { key: 'left', label: 'Left', viewMode: 'elevation_left' },
 30вҶ’  { key: 'right', label: 'Right', viewMode: 'elevation_right' },
 31вҶ’  { key: 'section', label: 'Section', viewMode: 'section_view' },
 32вҶ’];
 33вҶ’
 34вҶ’const toolItems = [
 35вҶ’  { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V', Icon: SelectIcon },
 36вҶ’  { tool: TOOLS.DIMENSION, label: 'Dimension', shortcut: 'M', Icon: DimensionIcon },
 37вҶ’  { tool: TOOLS.WALL, label: 'Wall', shortcut: 'W', Icon: WallIcon },
