 43вҶ’  { tool: TOOLS.DOOR, label: 'Door', shortcut: 'D', Icon: DoorIcon },
 44вҶ’  { tool: TOOLS.WINDOW, label: 'Window', shortcut: 'N', Icon: WindowIcon },
 45вҶ’  { tool: TOOLS.COLUMN, label: 'Column', shortcut: 'C', Icon: ColumnIcon },
 46вҶ’  { tool: TOOLS.LANDING, label: 'Landing', shortcut: 'L', Icon: LandingIcon },
 47вҶ’  { tool: TOOLS.RAILING, label: 'Railing', shortcut: 'H', Icon: RailingIcon },
 48вҶ’];
 49вҶ’
 50вҶ’export default function Toolbar({
 51вҶ’  onNew,
 52вҶ’  onSave,
 53вҶ’  onLoad,
 54вҶ’  isSidebarCollapsed,
 55вҶ’  isPropertiesCollapsed,
 56вҶ’  onToggleSidebar,
 57вҶ’  onToggleProperties,
 58вҶ’}) {
 59вҶ’  const {
 60вҶ’    activeTool,
 61вҶ’    showGrid,
 62вҶ’    snapEnabled,
 63вҶ’    activeFloorId,
 64вҶ’    viewMode,
 65вҶ’    workspaceMode,
 66вҶ’    modelTarget,
 67вҶ’    toolState,
 68вҶ’    activePhaseId,
 69вҶ’    selectedId,
 70вҶ’    selectedType,
 71вҶ’    dispatch: editorDispatch,
 72вҶ’  } = useEditor();
 73вҶ’  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 74вҶ’  const {
 75вҶ’    canCopySelection,
 76вҶ’    canPaste,
 77вҶ’    copySelection,
 78вҶ’    cutSelection,
 79вҶ’    beginPaste,
 80вҶ’  } = usePlanClipboardController();
 81вҶ’  const isPlanView = workspaceMode === 'model' && viewMode === 'plan' && modelTarget === 'floor';
 82вҶ’  const isRoofPlanView = workspaceMode === 'model' && viewMode === 'plan' && modelTarget === 'roof';
 83вҶ’  const isTrussPlanView = workspaceMode === 'model' && viewMode === 'plan' && modelTarget === 'truss';
 84вҶ’
 85вҶ’  const fixtureItems = [
 86вҶ’    { fixtureType: FIXTURE_TYPES.KITCHEN_TOP, label: 'Kitchen Top', Icon: KitchenTopIcon },
 87вҶ’    { fixtureType: FIXTURE_TYPES.TOILET, label: 'Toilet', Icon: ToiletIcon },
 88вҶ’    { fixtureType: FIXTURE_TYPES.LAVATORY, label: 'Lavatory', Icon: LavatoryIcon },
 89вҶ’    { fixtureType: FIXTURE_TYPES.TABLE, label: 'Table', Icon: TableIcon },
 90вҶ’    { fixtureType: FIXTURE_TYPES.TV, label: 'TV', Icon: TVIcon },
 91вҶ’    { fixtureType: FIXTURE_TYPES.SOFA, label: 'Sofa', Icon: SofaIcon },
