 93вҶ’  ];
 94вҶ’
 95вҶ’  const setTool = (tool) => {
 96вҶ’    editorDispatch({ type: 'SET_TOOL', tool });
 97вҶ’
 98вҶ’    if (tool !== TOOLS.TRUSS_DRAW || modelTarget !== 'truss') return;
 99вҶ’
100вҶ’    const targetTrussSystem = selectedType === 'trussSystem'
101вҶ’      ? (project.trussSystems || []).find((entry) => entry.id === selectedId) || null
102вҶ’      : selectedType === 'trussInstance'
103вҶ’        ? (project.trussSystems || []).find((entry) => (
104вҶ’            (entry.trussInstances || []).some((trussInstance) => trussInstance.id === selectedId)
105вҶ’          )) || null
106вҶ’        : null;
107вҶ’    const selectedTrussInstance = selectedType === 'trussInstance' && targetTrussSystem
108вҶ’      ? (targetTrussSystem.trussInstances || []).find((entry) => entry.id === selectedId) || null
109вҶ’      : null;
110вҶ’    const lastSystemInstance = targetTrussSystem && (targetTrussSystem.trussInstances || []).length
111вҶ’      ? targetTrussSystem.trussInstances[targetTrussSystem.trussInstances.length - 1]
112вҶ’      : null;
113вҶ’
114вҶ’    editorDispatch({
115вҶ’      type: 'UPDATE_TOOL_STATE',
116вҶ’      payload: {
117вҶ’        targetTrussSystemId: targetTrussSystem?.id || null,
118вҶ’        trussTypeId: selectedTrussInstance?.trussTypeId
119вҶ’          || lastSystemInstance?.trussTypeId
120вҶ’          || null,
121вҶ’        trussMaterial: selectedTrussInstance?.material
122вҶ’          || lastSystemInstance?.material
123вҶ’          || null,
124вҶ’      },
125вҶ’    });
126вҶ’  };
127вҶ’  const roofToolItems = [
128вҶ’    { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V', Icon: SelectIcon },
129вҶ’    { tool: TOOLS.ROOF_PARAPET, label: 'Parapet', shortcut: 'P', Icon: ParapetIcon },
130вҶ’    { tool: TOOLS.ROOF_DRAIN, label: 'Drain', shortcut: 'G', Icon: DrainIcon },
131вҶ’    { tool: TOOLS.ROOF_OPENING, label: 'Opening', shortcut: 'O', Icon: OpeningIcon },
132вҶ’  ];
133вҶ’  const trussToolItems = [
134вҶ’    { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V', Icon: SelectIcon },
135вҶ’    { tool: TOOLS.TRUSS_DRAW, label: 'Draw Truss', shortcut: 'T', Icon: TrussDrawIcon },
136вҶ’  ];
137вҶ’  const currentViewModes = modelTarget === 'truss'
138вҶ’    ? [
139вҶ’        { key: 'plan', label: 'Plan', viewMode: 'plan' },
140вҶ’        { key: 'detail', label: 'Detail', viewMode: 'truss_detail' },
141вҶ’        { key: 'section', label: 'Section', viewMode: 'section_view' },
142вҶ’      ]
143вҶ’    : viewModes;
144вҶ’
145вҶ’  const handleUndo = useCallback(() => {
146вҶ’    if (!canUndo) return;
147вҶ’    dispatch({ type: 'UNDO' });
148вҶ’    editorDispatch({ type: 'DESELECT' });
149вҶ’    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
150вҶ’  }, [canUndo, dispatch, editorDispatch]);
151вҶ’
152вҶ’  const handleRedo = useCallback(() => {
153вҶ’    if (!canRedo) return;
154вҶ’    dispatch({ type: 'REDO' });
155вҶ’    editorDispatch({ type: 'DESELECT' });
156вҶ’    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
157вҶ’  }, [canRedo, dispatch, editorDispatch]);
158вҶ’
159вҶ’  const handleDetectRooms = () => {
160вҶ’    const floor = project.floors.find(f => f.id === activeFloorId);
161вҶ’    if (!floor || floor.walls.length < 3) {
162вҶ’      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
163вҶ’      return;
164вҶ’    }
165вҶ’    const detected = detectRooms(floor.walls, floor.columns || []);
166вҶ’    const rooms = detected.map((d, i) => {
167вҶ’      const room = createRoom(`Room ${i + 1}`, d.points);
168вҶ’      room.phaseId = activePhaseId || null;
169вҶ’      return room;
170вҶ’    });
171вҶ’    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
172вҶ’    editorDispatch({ type: 'DESELECT' });
173вҶ’    editorDispatch({
174вҶ’      type: 'SET_STATUS_MESSAGE',
175вҶ’      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
176вҶ’    });
177вҶ’  };
178вҶ’
179вҶ’  useEffect(() => {
180вҶ’    const handleKeyDown = (e) => {
181вҶ’      if (!(e.ctrlKey || e.metaKey)) return;
182вҶ’      if (isTypingTarget(e.target)) return;
183вҶ’
184вҶ’      const key = e.key.toLowerCase();
185вҶ’      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
186вҶ’      const isUndo = key === 'z' && !e.shiftKey;
187вҶ’      if (!isUndo && !isRedo) return;
188вҶ’
189вҶ’      e.preventDefault();
190вҶ’      if (isRedo) {
191вҶ’        handleRedo();
192вҶ’        return;
193вҶ’      }
194вҶ’      handleUndo();
195вҶ’    };
196вҶ’
197вҶ’    window.addEventListener('keydown', handleKeyDown);
198вҶ’    return () => window.removeEventListener('keydown', handleKeyDown);
199вҶ’  }, [handleRedo, handleUndo]);
200вҶ’
201вҶ’  const activeViewKey = workspaceMode === 'sheet' ? 'sheets' :
202вҶ’    currentViewModes.find(v => v.viewMode === viewMode)?.key || 'plan';
203вҶ’
204вҶ’  return (
205вҶ’    <div className={styles.toolbar}>
206вҶ’      {/* File & clipboard actions */}
207вҶ’      <div className={styles.group}>
208вҶ’        <Tooltip label="New Project">
209вҶ’          <button className={styles.btn} onClick={onNew} aria-label="New Project">
210вҶ’            <NewIcon className={styles.icon} />
211вҶ’          </button>
212вҶ’        </Tooltip>
213вҶ’        <Tooltip label="Undo" shortcut="Ctrl+Z">
214вҶ’          <button
215вҶ’            className={styles.btn}
216вҶ’            onClick={handleUndo}
217вҶ’            disabled={!canUndo}
218вҶ’            aria-label="Undo"
219вҶ’          >
220вҶ’            <UndoIcon className={styles.icon} />
221вҶ’          </button>
222вҶ’        </Tooltip>
223вҶ’        <Tooltip label="Redo" shortcut="Ctrl+Shift+Z">
224вҶ’          <button
225вҶ’            className={styles.btn}
226вҶ’            onClick={handleRedo}
227вҶ’            disabled={!canRedo}
228вҶ’            aria-label="Redo"
229вҶ’          >
230вҶ’            <RedoIcon className={styles.icon} />
231вҶ’          </button>
232вҶ’        </Tooltip>
233вҶ’        <Tooltip label="Save" shortcut="Ctrl+S">
234вҶ’          <button
235вҶ’            className={styles.saveBtn}
236вҶ’            onClick={onSave}
237вҶ’            data-dirty={isDirty}
238вҶ’            aria-label="Save"
239вҶ’          >
240вҶ’            <SaveIcon className={styles.icon} />
241вҶ’          </button>
242вҶ’        </Tooltip>
243вҶ’        <div className={styles.divider} />
244вҶ’        <Tooltip label="Load Project">
245вҶ’          <button className={styles.btn} onClick={onLoad} aria-label="Load Project">
246вҶ’            <LoadIcon className={styles.icon} />
247вҶ’          </button>
248вҶ’        </Tooltip>
249вҶ’        <Tooltip label="Copy" shortcut="Ctrl+C">
250вҶ’          <button
251вҶ’            className={styles.btn}
252вҶ’            onClick={copySelection}
253вҶ’            disabled={!canCopySelection || modelTarget !== 'floor' || workspaceMode !== 'model'}
254вҶ’            aria-label="Copy"
255вҶ’          >
256вҶ’            <CopyIcon className={styles.icon} />
257вҶ’          </button>
258вҶ’        </Tooltip>
259вҶ’        <Tooltip label="Cut" shortcut="Ctrl+X">
260вҶ’          <button
261вҶ’            className={styles.btn}
262вҶ’            onClick={cutSelection}
263вҶ’            disabled={!canCopySelection || modelTarget !== 'floor' || workspaceMode !== 'model'}
264вҶ’            aria-label="Cut"
265вҶ’          >
266вҶ’            <CutIcon className={styles.icon} />
267вҶ’          </button>
268вҶ’        </Tooltip>
269вҶ’        <Tooltip label="Paste" shortcut="Ctrl+V">
270вҶ’          <button
271вҶ’            className={styles.btn}
272вҶ’            onClick={() => beginPaste()}
273вҶ’            disabled={!canPaste || modelTarget !== 'floor' || workspaceMode !== 'model'}
274вҶ’            aria-label="Paste"
275вҶ’          >
276вҶ’            <PasteIcon className={styles.icon} />
277вҶ’          </button>
278вҶ’        </Tooltip>
279вҶ’      </div>
280вҶ’
281вҶ’      <div className={styles.segmentedGroup}>
282вҶ’        <button
283вҶ’          className={workspaceMode === 'model' && modelTarget === 'floor' ? styles.segmentedBtnActive : styles.segmentedBtn}
284вҶ’          onClick={() => {
285вҶ’            editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'floor' });
286вҶ’            if (viewMode === 'truss_detail') {
287вҶ’              editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' });
288вҶ’            }
289вҶ’          }}
290вҶ’        >
291вҶ’          Floor
292вҶ’        </button>
293вҶ’        <button
294вҶ’          className={workspaceMode === 'model' && modelTarget === 'roof' ? styles.segmentedBtnActive : styles.segmentedBtn}
295вҶ’          onClick={() => {
296вҶ’            editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'roof' });
297вҶ’            if (viewMode === 'truss_detail') {
298вҶ’              editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' });
299вҶ’            }
300вҶ’          }}
301вҶ’        >
302вҶ’          Roof
303вҶ’        </button>
304вҶ’        <button
305вҶ’          className={workspaceMode === 'model' && modelTarget === 'truss' ? styles.segmentedBtnActive : styles.segmentedBtn}
306вҶ’          onClick={() => {
307вҶ’            editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'truss' });
308вҶ’            if (viewMode !== 'plan' && viewMode !== 'section_view' && viewMode !== 'truss_detail') {
309вҶ’              editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' });
310вҶ’            }
311вҶ’          }}
312вҶ’        >
313вҶ’          Truss
314вҶ’        </button>
315вҶ’        <button
316вҶ’          className={workspaceMode === 'sheet' ? styles.segmentedBtnActive : styles.segmentedBtn}
317вҶ’          onClick={() => editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' })}
318вҶ’        >
319вҶ’          Sheets
320вҶ’        </button>
321вҶ’      </div>
322вҶ’
323вҶ’      {/* View mode segmented control */}
324вҶ’      <div className={styles.segmentedGroup}>
325вҶ’        {currentViewModes.map(({ key, label, viewMode: vm }) => (
326вҶ’          <button
327вҶ’            key={key}
328вҶ’            className={activeViewKey === key ? styles.segmentedBtnActive : styles.segmentedBtn}
329вҶ’            onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: vm })}
330вҶ’          >
331вҶ’            {label}
332вҶ’          </button>
333вҶ’        ))}
334вҶ’      </div>
335вҶ’
336вҶ’      {/* Tool palette - inline row of icons */}
337вҶ’      <div className={styles.toolPalette}>
338вҶ’        <span className={styles.groupLabel}>Tools</span>
339вҶ’        {(modelTarget === 'roof' ? roofToolItems : (modelTarget === 'truss' ? trussToolItems : toolItems)).map(({ tool, label, shortcut, Icon }) => (
340вҶ’          <Tooltip key={tool} label={label} shortcut={shortcut}>
341вҶ’            <button
342вҶ’              className={activeTool === tool ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
343вҶ’              onClick={() => setTool(tool)}
344вҶ’              disabled={modelTarget === 'roof' ? !isRoofPlanView : (modelTarget === 'truss' ? !isTrussPlanView : !isPlanView)}
345вҶ’              aria-label={label}
346вҶ’            >
347вҶ’              <Icon className={styles.toolPaletteIcon} />
348вҶ’            </button>
349вҶ’          </Tooltip>
350вҶ’        ))}
351вҶ’      </div>
352вҶ’
353вҶ’      {/* Fixtures palette */}
354вҶ’      <div className={styles.fixturePalette}>
355вҶ’        <span className={styles.fixturePaletteLabel}>Fixtures</span>
356вҶ’        {fixtureItems.map(({ fixtureType, label, Icon }) => {
357вҶ’          const isActive = activeTool === TOOLS.FIXTURE && toolState.fixtureType === fixtureType;
358вҶ’          return (
359вҶ’            <Tooltip key={fixtureType} label={label} shortcut="F">
360вҶ’              <button
361вҶ’                className={isActive ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
362вҶ’                onClick={() => {
363вҶ’                  editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
364вҶ’                  editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType, previewRotation: 0 } });
365вҶ’                }}
366вҶ’                disabled={!isPlanView}
367вҶ’                aria-label={label}
368вҶ’              >
369вҶ’                <Icon className={styles.toolPaletteIcon} />
370вҶ’              </button>
371вҶ’            </Tooltip>
372вҶ’          );
373вҶ’        })}
374вҶ’      </div>
375вҶ’
376вҶ’      {/* Panel toggles & utility toggles */}
377вҶ’      <div className={styles.group}>
378вҶ’        <span className={styles.groupLabel}>Panels</span>
379вҶ’        <Tooltip label={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}>
380вҶ’          <button
381вҶ’            className={`${styles.toggleBtn} ${!isSidebarCollapsed ? styles.toggleActive : ''}`}
382вҶ’            onClick={onToggleSidebar}
383вҶ’            aria-label={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
384вҶ’          >
385вҶ’            <SidebarIcon className={styles.icon} />
386вҶ’          </button>
387вҶ’        </Tooltip>
388вҶ’        <Tooltip label={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}>
389вҶ’          <button
390вҶ’            className={`${styles.toggleBtn} ${!isPropertiesCollapsed ? styles.toggleActive : ''}`}
391вҶ’            onClick={onToggleProperties}
392вҶ’            aria-label={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
393вҶ’          >
394вҶ’            <PropertiesIcon className={styles.icon} />
395вҶ’          </button>
396вҶ’        </Tooltip>
397вҶ’        <div className={styles.divider} />
398вҶ’        <span className={styles.groupLabel}>Display</span>
399вҶ’        <Tooltip label="Toggle Grid">
400вҶ’          <button
401вҶ’            className={`${styles.toggleBtn} ${showGrid ? styles.toggleActive : ''}`}
402вҶ’            onClick={() => editorDispatch({ type: 'TOGGLE_GRID' })}
403вҶ’            aria-label="Toggle Grid"
404вҶ’          >
405вҶ’            <GridIcon className={styles.icon} />
406вҶ’          </button>
407вҶ’        </Tooltip>
408вҶ’        <Tooltip label="Toggle Snap">
409вҶ’          <button
410вҶ’            className={`${styles.toggleBtn} ${snapEnabled ? styles.toggleActive : ''}`}
411вҶ’            onClick={() => editorDispatch({ type: 'TOGGLE_SNAP' })}
412вҶ’            aria-label="Toggle Snap"
413вҶ’          >
414вҶ’            <SnapIcon className={styles.icon} />
415вҶ’          </button>
416вҶ’        </Tooltip>
417вҶ’        <Tooltip label="Auto-detect Rooms">
418вҶ’          <button
419вҶ’            className={styles.btn}
420вҶ’            onClick={handleDetectRooms}
421вҶ’            disabled={!isPlanView}
422вҶ’            aria-label="Auto-detect Rooms"
423вҶ’          >
424вҶ’            <DetectRoomsIcon className={styles.icon} />
425вҶ’          </button>
426вҶ’        </Tooltip>
427вҶ’      </div>
428вҶ’
429вҶ’      <div className={styles.spacer} />
430вҶ’    </div>
431вҶ’  );
432вҶ’}
