 18вҶ’function hitTest(modelPos, floor, annotationTolerance) {
 19вҶ’  // Hit test doors first (smaller targets, higher priority)
 20вҶ’  for (const door of floor.doors) {
 21вҶ’    const wall = floor.walls.find(w => w.id === door.wallId);
 22вҶ’    if (!wall) continue;
 23вҶ’    const info = doorOutlineOnWall(wall, door);
 24вҶ’    const poly = [info.p1, info.p2, info.p3, info.p4];
 25вҶ’    if (pointInPolygon(modelPos, poly)) {
 26вҶ’      return { id: door.id, type: 'door' };
 27вҶ’    }
 28вҶ’  }
 29вҶ’
 30вҶ’  // Hit test windows
 31вҶ’  for (const win of floor.windows) {
 32вҶ’    const wall = floor.walls.find(w => w.id === win.wallId);
 33вҶ’    if (!wall) continue;
 34вҶ’    const info = windowOutlineOnWall(wall, win);
 35вҶ’    const poly = [info.p1, info.p2, info.p3, info.p4];
 36вҶ’    if (pointInPolygon(modelPos, poly)) {
 37вҶ’      return { id: win.id, type: 'window' };
 38вҶ’    }
 39вҶ’  }
 40вҶ’
 41вҶ’  // Hit test walls
 42вҶ’  // Hit test columns
 43вҶ’  for (const sc of (floor.sectionCuts || [])) {
 44вҶ’    if (hitTestSectionCut(modelPos, sc, annotationTolerance)) {
 45вҶ’      return { id: sc.id, type: 'sectionCut' };
 46вҶ’    }
 47вҶ’  }
 48вҶ’
 49вҶ’  for (const column of (floor.columns || [])) {
 50вҶ’    const outline = columnOutline(column);
 51вҶ’    if (pointInPolygon(modelPos, outline)) {
 52вҶ’      return { id: column.id, type: 'column' };
 53вҶ’    }
 54вҶ’  }
 55вҶ’
 56вҶ’  // Hit test fixtures
 57вҶ’  for (const fixture of (floor.fixtures || [])) {
 58вҶ’    if (fixtureContainsPoint(fixture, modelPos)) {
 59вҶ’      return { id: fixture.id, type: 'fixture' };
 60вҶ’    }
 61вҶ’  }
 62вҶ’
 63вҶ’  // Hit test railings
 64вҶ’  for (const railing of (floor.railings || [])) {
 65вҶ’    if (railingContainsPoint(railing, modelPos)) {
 66вҶ’      return { id: railing.id, type: 'railing' };
 67вҶ’    }
 68вҶ’  }
 69вҶ’
 70вҶ’  // Hit test beams
 71вҶ’  for (const beam of (floor.beams || [])) {
 72вҶ’    const renderData = getBeamRenderData(beam, floor.columns || []);
 73вҶ’    if (!renderData) continue;
 74вҶ’    if (pointInPolygon(modelPos, renderData.outline)) {
 75вҶ’      return { id: beam.id, type: 'beam' };
 76вҶ’    }
 77вҶ’  }
 78вҶ’
 79вҶ’  // Hit test walls
 80вҶ’  for (const wall of floor.walls) {
 81вҶ’    const outline = getWallRenderData(wall, floor.columns || []).outline;
 82вҶ’    if (pointInPolygon(modelPos, outline)) {
 83вҶ’      return { id: wall.id, type: 'wall' };
 84вҶ’    }
 85вҶ’  }
 86вҶ’
 87вҶ’  // Hit test stairs after walls/beams/columns so current editing priority stays intact.
 88вҶ’  for (const stair of (floor.stairs || [])) {
 89вҶ’    const renderData = getStairRenderData(stair);
 90вҶ’    if (!renderData) continue;
 91вҶ’    if (pointInPolygon(modelPos, renderData.outline)) {
 92вҶ’      return { id: stair.id, type: 'stair' };
 93вҶ’    }
 94вҶ’  }
 95вҶ’
 96вҶ’  // Hit test landings
 97вҶ’  for (const landing of (floor.landings || [])) {
 98вҶ’    if (landingContainsPoint(landing, modelPos)) {
 99вҶ’      return { id: landing.id, type: 'landing' };
100вҶ’    }

