 6вҶ’function constrainAngle(start, end, shiftHeld) {
 7вҶ’  if (!shiftHeld) return end;
 8вҶ’  const dx = end.x - start.x;
 9вҶ’  const dy = end.y - start.y;
10вҶ’  const angle = Math.atan2(dy, dx);
11вҶ’  const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
12вҶ’  const len = Math.sqrt(dx * dx + dy * dy);
13вҶ’  return {
14вҶ’    x: start.x + Math.cos(snapAngle) * len,
15вҶ’    y: start.y + Math.sin(snapAngle) * len,
16вҶ’  };
17вҶ’}
