19вҶ’export function createWallDrawHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled, activePhaseId }) {
20вҶ’  return {
21вҶ’    onMouseDown(modelPos, e, toolState) {
22вҶ’      if (e.button !== 0) return;
23вҶ’
24вҶ’      const floor = getFloor(activeFloorId);
25вҶ’      if (!floor) return;
26вҶ’      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
27вҶ’      const shiftHeld = e.shiftKey;
28вҶ’
29вҶ’      let snapped = modelPos;
30вҶ’      let attachment = null;
31вҶ’      if (snapEnabled) {
32вҶ’        const snapResult = snapWallEndpoint(modelPos, {
33вҶ’          walls: floor.walls,
34вҶ’          columns: floor.columns || [],
35вҶ’          snapDist: snapDistModel,
36вҶ’          chainStart: toolState.chainStart,
37вҶ’          otherPoint: toolState.start,
38вҶ’        });
39вҶ’        if (snapResult) {
40вҶ’          snapped = { ...snapResult.point };
41вҶ’          attachment = snapResult.attachment;
42вҶ’        }
43вҶ’      }
44вҶ’      if (shiftHeld && toolState.start) {
45вҶ’        snapped = constrainAngle(toolState.start, snapped, true);
46вҶ’        attachment = null;
47вҶ’      }
48вҶ’
49вҶ’      if (!toolState.start) {
50вҶ’        // First click: set start
51вҶ’        editorDispatch({
52вҶ’          type: 'UPDATE_TOOL_STATE',
53вҶ’          payload: { start: snapped, chainStart: snapped, startAttachment: attachment, preview: null },
54вҶ’        });
55вҶ’      } else {
56вҶ’        // Second+ click: create wall and chain
57вҶ’        const endPt = snapped;
58вҶ’
59вҶ’        const len = distance(toolState.start, endPt);
60вҶ’        if (len < MIN_WALL_LENGTH) return;
61вҶ’
62вҶ’        const wall = createWall(toolState.start, endPt, undefined, {
63вҶ’          startAttachment: toolState.startAttachment || null,
64вҶ’          endAttachment: attachment,
65вҶ’        });
66вҶ’        wall.phaseId = activePhaseId || null;
67вҶ’        dispatch({ type: 'WALL_ADD', floorId: activeFloorId, wall });
68вҶ’
69вҶ’        // Check if we snapped back to chain start (close loop)
70вҶ’        if (toolState.chainStart && distance(endPt, toolState.chainStart) < snapDistModel) {
71вҶ’          editorDispatch({
72вҶ’            type: 'UPDATE_TOOL_STATE',
73вҶ’            payload: { start: null, chainStart: null, startAttachment: null, preview: null },
74вҶ’          });
75вҶ’        } else {
76вҶ’          // Chain: end becomes new start
77вҶ’          editorDispatch({
78вҶ’            type: 'UPDATE_TOOL_STATE',
79вҶ’            payload: { start: endPt, startAttachment: attachment, preview: null },
80вҶ’          });

