 64вҶ’        workspaceMode: action.workspaceMode,
 65вҶ’        viewport: action.workspaceMode === 'sheet'
 66вҶ’          ? { ...state.sheetViewport }
 67вҶ’          : { ...state.modelViewport },
 68вҶ’        toolState: {},
 69вҶ’        statusMessage: null,
 70вҶ’      };
 71вҶ’
 72вҶ’    case 'SET_ACTIVE_SHEET':
