247вҶ’export function EditorProvider({ children, initialActiveFloorId = null, availableFloorIds = [], availablePhaseIds = [] }) {
248вҶ’  const [state, dispatch] = useReducer(
249вҶ’    editorReducer,
250вҶ’    initialActiveFloorId,
