258вҶ’      }
259вҶ’      return;
260вҶ’    }
261вҶ’
262вҶ’    if (!state.activeFloorId || !availableFloorIds.includes(state.activeFloorId)) {
263вҶ’      dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: availableFloorIds[0] });
264вҶ’    }
265вҶ’  }, [availableFloorIds, state.activeFloorId]);
