 92вҶ’  return (
 93вҶ’    <rect
 94вҶ’      x={x}
 95вҶ’      y={tag.position.y - height / 2}
 96вҶ’      width={width}
 97вҶ’      height={height}
 98вҶ’      fill={SHEET_COLORS.mask}
 99вҶ’      opacity={opacity}
100вҶ’      transform={`rotate(${tag.angle || 0}, ${tag.position.x}, ${tag.position.y})`}
101вҶ’    />
102вҶ’  );
103вҶ’}
