113вҶ’      textFill: DRAWING_GRAPHICS.annotation.text,
114вҶ’      fontWeight: 600,
115вҶ’      maskOpacity: 0.92,
116вҶ’      leaderStroke: DRAWING_GRAPHICS.annotation.dimensionExtension,
117вҶ’      leaderDash: undefined,
118вҶ’    };
119вҶ’  }
120вҶ’
121вҶ’  if (isInformationalMeasurement) {
122вҶ’    return {
