117вҶ’function AppInner() {
118вҶ’  const { project, isDirty, dispatch } = useProject();
119вҶ’  const orderedFloors = useMemo(() => getOrderedFloors(project), [project]);
120вҶ’  const availableFloorIds = useMemo(() => orderedFloors.map((floor) => floor.id), [orderedFloors]);
121вҶ’  const availablePhaseIds = useMemo(() => (project.phases || []).map((p) => p.id), [project.phases]);
122вҶ’  const initialActiveFloorId = getDefaultActiveFloorId(project);
123вҶ’  const [showLoadModal, setShowLoadModal] = useState(false);
124вҶ’  const [showNewProjectModal, setShowNewProjectModal] = useState(false);
125вҶ’  const [savedProjects, setSavedProjects] = useState([]);
126вҶ’  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
127вҶ’  const [isPropertiesCollapsed, setIsPropertiesCollapsed] = useState(false);
128вҶ’  const [projectFileHandle, setProjectFileHandle] = useState(null);
129вҶ’  const importInputRef = useRef(null);
130вҶ’
131вҶ’  useAutosave(project, isDirty, dispatch);
132вҶ’
133вҶ’  // beforeunload warning
134вҶ’  useEffect(() => {
135вҶ’    const handler = (e) => {
136вҶ’      if (isDirty) {
137вҶ’        e.preventDefault();
138вҶ’        e.returnValue = '';
139вҶ’      }
140вҶ’    };
141вҶ’    window.addEventListener('beforeunload', handler);
142вҶ’    return () => window.removeEventListener('beforeunload', handler);
143вҶ’  }, [isDirty]);
144вҶ’
145вҶ’  const handleNew = useCallback(() => {
146вҶ’    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
147вҶ’    setShowNewProjectModal(true);
148вҶ’  }, [isDirty]);
149вҶ’
150вҶ’  const handleCreateProject = useCallback(({ name }) => {
151вҶ’    const newProject = createProject(name);
152вҶ’    setProjectFileHandle(null);
153вҶ’    dispatch({ type: 'PROJECT_NEW', project: newProject });
154вҶ’    setShowNewProjectModal(false);
155вҶ’  }, [dispatch]);
156вҶ’
157вҶ’  const handleSave = useCallback(async () => {
158вҶ’    try {
159вҶ’      const { fileHandle } = await exportProjectFile(project, { fileHandle: projectFileHandle });
160вҶ’      setProjectFileHandle(fileHandle);
161вҶ’      try {
162вҶ’        await saveProject(project);
163вҶ’      } catch {
164вҶ’        // Browser draft sync is secondary to file save.
165вҶ’      }
166вҶ’      dispatch({ type: 'MARK_SAVED' });
167вҶ’    } catch (err) {
168вҶ’      if (isFilePickerAbortError(err)) return;
169вҶ’      alert('Failed to save project file: ' + err.message);
170вҶ’    }
171вҶ’  }, [project, projectFileHandle, dispatch]);
172вҶ’
173вҶ’  // Ctrl+S save
174вҶ’  useEffect(() => {
175вҶ’    const handler = (e) => {
176вҶ’      if (isTypingTarget(e.target)) return;
177вҶ’      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
178вҶ’        e.preventDefault();
179вҶ’        handleSave();
180вҶ’      }
181вҶ’    };
182вҶ’    window.addEventListener('keydown', handler);
183вҶ’    return () => window.removeEventListener('keydown', handler);
184вҶ’  }, [handleSave]);
185вҶ’
186вҶ’  const handleLoadClick = useCallback(async () => {
187вҶ’    setSavedProjects(await listProjects());
188вҶ’    setShowLoadModal(true);
189вҶ’  }, []);
190вҶ’
191вҶ’  const handleOpenProjectFile = useCallback(async () => {
192вҶ’    if (typeof window.showOpenFilePicker !== 'function') {
193вҶ’      importInputRef.current?.click();
194вҶ’      return;
195вҶ’    }
196вҶ’
197вҶ’    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
198вҶ’      return;
199вҶ’    }
200вҶ’
201вҶ’    try {
202вҶ’      const { project: loaded, savedAt, fileHandle } = await openProjectFile();
203вҶ’      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
204вҶ’      setProjectFileHandle(fileHandle);
205вҶ’      setShowLoadModal(false);
206вҶ’    } catch (err) {
207вҶ’      if (isFilePickerAbortError(err)) return;
208вҶ’      alert('Failed to import project file: ' + err.message);
209вҶ’    }
210вҶ’  }, [isDirty, dispatch]);
211вҶ’
212вҶ’  const handleImportFile = useCallback(async (e) => {
213вҶ’    const file = e.target.files?.[0] || null;
214вҶ’    e.target.value = '';
215вҶ’    if (!file) return;
216вҶ’
217вҶ’    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
218вҶ’      return;
219вҶ’    }
220вҶ’
221вҶ’    try {
222вҶ’      const { project: loaded, savedAt } = await importProjectFile(file);
223вҶ’      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
224вҶ’      setProjectFileHandle(null);
225вҶ’      setShowLoadModal(false);
226вҶ’    } catch (err) {
227вҶ’      alert('Failed to import project file: ' + err.message);
228вҶ’    }
229вҶ’  }, [isDirty, dispatch]);
230вҶ’
231вҶ’  const handleLoad = useCallback(async (id) => {
232вҶ’    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
233вҶ’    try {
234вҶ’      const { project: loaded, savedAt } = await loadProject(id);
235вҶ’      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
236вҶ’      setProjectFileHandle(null);
237вҶ’      setShowLoadModal(false);
238вҶ’    } catch (err) {
239вҶ’      alert('Failed to load project: ' + err.message);
240вҶ’    }
241вҶ’  }, [isDirty, dispatch]);
242вҶ’
243вҶ’  const handleDelete = useCallback(async (id, name) => {
244вҶ’    const confirmed = window.confirm(`Delete "${name}"? This cannot be undone.`);
245вҶ’    if (!confirmed) return;
246вҶ’
247вҶ’    try {
248вҶ’      await deleteProject(id);
249вҶ’      setSavedProjects(projects => projects.filter(project => project.id !== id));
250вҶ’    } catch (err) {
251вҶ’      alert('Failed to delete project: ' + err.message);
252вҶ’    }
253вҶ’  }, []);
254вҶ’
255вҶ’  return (
256вҶ’    <EditorProvider
257вҶ’      initialActiveFloorId={initialActiveFloorId}
258вҶ’      availableFloorIds={availableFloorIds}
259вҶ’      availablePhaseIds={availablePhaseIds}
260вҶ’    >
261вҶ’      <input
262вҶ’        ref={importInputRef}
263вҶ’        type="file"
264вҶ’        accept=".json,application/json"
265вҶ’        onChange={handleImportFile}
266вҶ’        style={{ display: 'none' }}
267вҶ’      />
268вҶ’
269вҶ’      <EditorShell
270вҶ’        project={project}
271вҶ’        handleNew={handleNew}
272вҶ’        handleSave={handleSave}
273вҶ’        handleLoadClick={handleLoadClick}
274вҶ’        isSidebarCollapsed={isSidebarCollapsed}
275вҶ’        isPropertiesCollapsed={isPropertiesCollapsed}
276вҶ’        onToggleSidebar={() => setIsSidebarCollapsed(value => !value)}
277вҶ’        onToggleProperties={() => setIsPropertiesCollapsed(value => !value)}
278вҶ’      />
279вҶ’
280вҶ’      {showNewProjectModal && (
281вҶ’        <NewProjectModal
282вҶ’          onConfirm={handleCreateProject}
283вҶ’          onClose={() => setShowNewProjectModal(false)}
284вҶ’        />
285вҶ’      )}
286вҶ’
287вҶ’      {showLoadModal && (
288вҶ’        <Modal title="Open Project" onClose={() => setShowLoadModal(false)}>
289вҶ’          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
290вҶ’            <div className={modalStyles.modalCard}>
291вҶ’              <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
292вҶ’                <span className={modalStyles.modalCardTitle}>Project File</span>
293вҶ’                <span className={modalStyles.modalCardDesc}>
294вҶ’                  Open a JSON file previously saved to your computer.
295вҶ’                </span>
296вҶ’              </div>
297вҶ’              <button className={modalStyles.modalBtn} onClick={handleOpenProjectFile} style={{ alignSelf: 'flex-start' }}>
298вҶ’                Open Project File
299вҶ’              </button>
300вҶ’            </div>
301вҶ’
302вҶ’            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
303вҶ’              <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
304вҶ’                <span className={modalStyles.modalCardTitle}>Browser Drafts</span>
305вҶ’                <span className={modalStyles.modalCardDesc} style={{ fontSize: '11px' }}>
306вҶ’                  Stored only in this browser on this machine.
307вҶ’                </span>
308вҶ’              </div>
309вҶ’              {savedProjects.length === 0 ? (
310вҶ’                <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px', margin: 0 }}>
311вҶ’                  No browser drafts found.
312вҶ’                </p>
313вҶ’              ) : (
314вҶ’                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
315вҶ’                  {savedProjects.map(p => (
316вҶ’                    <div key={p.id} className={modalStyles.modalCard} style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
317вҶ’                      <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
318вҶ’                        <span style={{ fontWeight: 500, fontSize: '13px' }}>{p.name}</span>
319вҶ’                        <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
320вҶ’                          {new Date(p.savedAt).toLocaleDateString()}
321вҶ’                        </span>
322вҶ’                      </div>
323вҶ’                      <div style={{ display: 'flex', gap: '8px' }}>
324вҶ’                        <button className={modalStyles.modalBtn} onClick={() => handleLoad(p.id)}>Load</button>
325вҶ’                        <button className={modalStyles.modalBtnDanger} onClick={() => handleDelete(p.id, p.name)}>Delete</button>
326вҶ’                      </div>
327вҶ’                    </div>
328вҶ’                  ))}
329вҶ’                </div>
330вҶ’              )}
331вҶ’            </div>
332вҶ’          </div>
333вҶ’          <button className={modalStyles.modalBtn} onClick={() => setShowLoadModal(false)} style={{ marginTop: '16px' }}>
334вҶ’            Cancel
335вҶ’          </button>
336вҶ’        </Modal>
337вҶ’      )}
338вҶ’    </EditorProvider>
339вҶ’  );
340вҶ’}
