file.content:
@import './reset.css';
@import './variables.css';

html, body, #root {
  height: 100%;
  width: 100%;
  overflow: hidden;
}

body {
  font-family: var(--font-ui);
  font-size: 13px;
  color: var(--color-text-primary);
  background: var(--color-background);
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}

/* Custom scrollbars вҖ” light theme */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: rgba(0, 0, 0, 0.15);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(0, 0, 0, 0.25);
}

/* Selection highlight */
::selection {
  background: rgba(26, 122, 104, 0.15);
}

/* Focus ring */
:focus-visible {
  outline: 2px solid var(--color-accent);
  outline-offset: 1px;
}

/* Global input focus */
input:not([readonly]):focus,
select:focus {
  border-color: var(--color-accent) !important;
  box-shadow: 0 0 0 2px rgba(26, 122, 104, 0.15);
  outline: none;
}

/* Modal animations */
@keyframes modalOverlayIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes modalDialogIn {
  from {
    opacity: 0;
    transform: scale(0.96) translateY(8px);
  }
  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(4px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
}

@keyframes warmPulse {
  0%, 100% {
    box-shadow: 0 0 6px rgba(45, 95, 142, 0.40);
  }
  50% {
    box-shadow: 0 0 12px rgba(45, 95, 142, 0.60);
  }
}

@keyframes toastSlideUp {
  from {
    opacity: 0;
    transform: translateY(8px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes toastCountdown {
  from { width: 100%; }
  to { width: 0%; }
}
